const item = $input.first().json || {};

// =========================
// Helpers
// =========================
function safeObj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : {};
}

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function normalizeText(v) {
  return safeStr(v)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function hasValue(v) {
  return safeStr(v) !== '';
}

function clamp(num, min, max) {
  return Math.max(min, Math.min(max, num));
}

function uniq(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function textLen(v) {
  return safeStr(v).length;
}

function isLikelyMeaningfulText(v, min = 8) {
  return textLen(v) >= min;
}

function countFilledFields(obj = {}, keys = []) {
  return keys.filter(k => hasValue(obj[k])).length;
}

function countTrue(arr) {
  return arr.filter(Boolean).length;
}

function anyIncludes(text, terms = []) {
  const t = normalizeText(text);
  return terms.some(term => t.includes(normalizeText(term)));
}

function scoreByCompleteness(filled, maxFilled, maxScore) {
  if (maxFilled <= 0) return 0;
  return Math.round((filled / maxFilled) * maxScore);
}

function scoreFromBands(value, bands) {
  for (const band of bands) {
    if (value >= band.min) return band.score;
  }
  return 0;
}

function collectTexts(obj) {
  const texts = [];

  function walk(v) {
    if (v === null || v === undefined) return;

    if (typeof v === 'string' || typeof v === 'number' || typeof v === 'boolean') {
      const s = safeStr(v);
      if (s) texts.push(s);
      return;
    }

    if (Array.isArray(v)) {
      v.forEach(walk);
      return;
    }

    if (typeof v === 'object') {
      Object.values(v).forEach(walk);
    }
  }

  walk(obj);
  return texts.join(' | ');
}

// =========================
// Base extraction
// =========================
const message = safeObj(item.message);
const lead = safeObj(item.lead);
const chatwoot = safeObj(item.chatwoot);
const inputs = safeObj(item.inputs);
const atlas = safeObj(item.atlas);

const leadSummary = safeObj(inputs.lead_summary);
const agenda = safeObj(inputs.agenda);

const identificacao = safeObj(leadSummary.identificacao);
const cenario = safeObj(leadSummary.cenario);
const demanda = safeObj(leadSummary.demanda);
const conversa = safeObj(leadSummary.conversa);

const phone = safeStr(lead.phone);
const entry_channel = safeStr(lead.entry_channel);
const lead_status = safeStr(inputs.lead_status);
const last_intent = safeStr(inputs.last_intent);

const company_name =
  safeStr(lead.company_name) ||
  safeStr(identificacao.empresa) ||
  safeStr(item.company_name);

const instagram =
  safeStr(lead.instagram) ||
  safeStr(item.instagram);

const website =
  safeStr(lead.website) ||
  safeStr(item.website);

const google_business_profile =
  safeStr(lead.google_business_profile) ||
  safeStr(item.google_business_profile);

const email =
  safeStr(agenda.email) ||
  safeStr(inputs.email);

const last_user_message =
  safeStr(inputs.last_user_message) ||
  safeStr(message.content);

const last_ai_message =
  safeStr(inputs.last_ai_message) ||
  safeStr(message.answer) ||
  safeStr(message.clean_answer);

const objectiveText = safeStr(demanda.objetivo);
const painText = safeStr(demanda.dor_principal);
const investmentText = safeStr(demanda.investimento);
const decisionMakerText = safeStr(demanda.decisor);
const nicheText = safeStr(cenario.nicho);
const salesChannelText = safeStr(cenario.canal_venda);
const structureText = safeStr(cenario.estrutura);
const momentText = safeStr(cenario.momento);
const serviceInterestText = safeStr(cenario.servico_interesse);
const objectionsText = safeStr(conversa.objecoes);
const contextText = safeStr(conversa.ultimo_contexto);
const activeAssetsText = safeStr(identificacao.ativos_digitais);

const selected_option = safeStr(agenda.selected_option);
const selected_option_start = safeStr(agenda.selected_option_start);
const option_1_start = safeStr(agenda.option_1_start);
const option_2_start = safeStr(agenda.option_2_start);

const fullText = collectTexts(item);

// =========================
// Quality / completeness maps
// =========================
const summaryFilled = countFilledFields(identificacao, ['nome', 'empresa', 'ativos_digitais']) +
  countFilledFields(cenario, ['nicho', 'servico_interesse', 'canal_venda', 'estrutura', 'momento']) +
  countFilledFields(demanda, ['objetivo', 'dor_principal', 'investimento', 'decisor']) +
  countFilledFields(conversa, ['objecoes', 'ultimo_contexto', 'proxima_etapa', 'encerramento']);

const summaryCompleteness = summaryFilled; // total out of 16

const strongTextCount = countTrue([
  isLikelyMeaningfulText(company_name, 3),
  isLikelyMeaningfulText(objectiveText, 10),
  isLikelyMeaningfulText(painText, 10),
  isLikelyMeaningfulText(salesChannelText, 5),
  isLikelyMeaningfulText(structureText, 5),
  isLikelyMeaningfulText(momentText, 5),
  isLikelyMeaningfulText(investmentText, 5),
  isLikelyMeaningfulText(decisionMakerText, 5),
  isLikelyMeaningfulText(contextText, 10),
  isLikelyMeaningfulText(last_user_message, 12)
]);

// =========================
// Soft semantic signals
// =========================
const has_company_name = hasValue(company_name);
const has_instagram = hasValue(instagram) || anyIncludes(activeAssetsText, ['instagram']);
const has_website = hasValue(website) || anyIncludes(activeAssetsText, ['site']);
const has_gbp = hasValue(google_business_profile) || anyIncludes(activeAssetsText, ['google', 'meu negocio', 'meu negócio', 'gmn']);

const identifierCount = countTrue([
  has_company_name,
  has_instagram,
  has_website,
  has_gbp
]);

const has_identifier = identifierCount >= 1;
const has_strong_identifier = identifierCount >= 2;

// negócio definido
const businessDensity = countTrue([
  has_company_name,
  hasValue(nicheText),
  hasValue(serviceInterestText),
  hasValue(salesChannelText),
  hasValue(structureText)
]);

const has_defined_business = businessDensity >= 2 || has_company_name;
const has_partial_business = businessDensity >= 1;

// já vende
const sellsDensity = countTrue([
  hasValue(salesChannelText),
  anyIncludes(fullText, ['vende', 'vendas', 'clientes', 'agendamentos', 'pacientes', 'demanda', 'faturamento']),
  anyIncludes(fullText, ['whatsapp', 'instagram', 'site', 'comercial']),
  hasValue(momentText)
]);

const already_sells_consistently = sellsDensity >= 3;
const already_sells_somewhat = sellsDensity >= 2;
const starting_to_sell = sellsDensity >= 1;

// decisor
const decisorDensity = countTrue([
  hasValue(decisionMakerText),
  anyIncludes(decisionMakerText, ['dono', 'proprietario', 'proprietário', 'socio', 'sócio', 'decisor']),
  anyIncludes(fullText, ['sou dono', 'sou o dono', 'sou socio', 'sou sócio', 'eu decido', 'minha empresa']),
  anyIncludes(fullText, ['falo com dono', 'consigo encaminhar', 'vou falar com o dono', 'tenho acesso'])
]);

const is_decisor =
  anyIncludes(decisionMakerText, ['dono', 'proprietario', 'proprietário', 'socio', 'sócio', 'decisor']) ||
  anyIncludes(fullText, ['sou dono', 'sou o dono', 'sou socio', 'sou sócio', 'eu decido', 'minha empresa']);

const has_access_to_decisor =
  !is_decisor &&
  anyIncludes(fullText, ['falo com dono', 'consigo encaminhar', 'vou falar com o dono', 'tenho acesso', 'passo para o decisor']);

const partial_access_to_decisor = !is_decisor && !has_access_to_decisor && decisorDensity >= 1;

// objetivo
const goalDensity = countTrue([
  hasValue(objectiveText),
  anyIncludes(objectiveText, ['crescer', 'clientes', 'vendas', 'agendamentos', 'escala', 'estrutura']),
  anyIncludes(fullText, ['quero crescer', 'mais clientes', 'mais vendas', 'mais agendamentos', 'escalar', 'estruturar']),
  hasValue(serviceInterestText)
]);

const clear_goal = goalDensity >= 2 && (textLen(objectiveText) >= 10 || anyIncludes(fullText, ['quero', 'preciso']));
const semi_clear_goal = goalDensity >= 1;
const generic_goal = goalDensity >= 0;

// dor
const painDensity = countTrue([
  hasValue(painText),
  anyIncludes(painText, ['dor', 'gargalo', 'problema', 'travado', 'previsibilidade', 'conversao', 'conversão']),
  anyIncludes(fullText, ['problema', 'dificuldade', 'gargalo', 'travado', 'sem previsibilidade', 'nao converte', 'não converte', 'perco lead']),
  hasValue(objectionsText)
]);

const strong_pain = painDensity >= 2 && (textLen(painText) >= 10 || textLen(contextText) >= 18);
const relevant_pain = painDensity >= 1;
const surface_pain = painDensity >= 0;

// urgência
const timingDensity = countTrue([
  hasValue(momentText),
  anyIncludes(momentText, ['agora', 'urgente', 'breve', 'esse mes', 'esse mês', 'logo']),
  anyIncludes(fullText, ['agora', 'urgente', 'o quanto antes', 'essa semana', 'esse mes', 'esse mês', 'logo']),
  anyIncludes(fullText, ['avaliando agora', 'quero começar'])
]);

const hot_timing = timingDensity >= 2 && anyIncludes(fullText + ' ' + momentText, ['agora', 'urgente', 'essa semana', 'o quanto antes']);
const soon_timing = timingDensity >= 2;
const brief_timing = timingDensity >= 1;
const someday_timing = timingDensity === 0 && anyIncludes(fullText, ['mais pra frente', 'futuro', 'sem pressa']);

// execução
const executionDensity = countTrue([
  hasValue(salesChannelText),
  hasValue(structureText),
  anyIncludes(fullText, ['equipe', 'time', 'vendedor', 'comercial', 'crm', 'script', 'pipeline', 'funil']),
  anyIncludes(fullText, ['whatsapp', 'instagram', 'site', 'atendimento']),
  hasValue(momentText)
]);

const clear_sales_channel = hasValue(salesChannelText);
const basic_sales_channel = clear_sales_channel || anyIncludes(fullText, ['whatsapp', 'instagram', 'site', 'google']);
const improvised_channel = !basic_sales_channel && executionDensity <= 1;

const has_team_structure = anyIncludes(structureText + ' ' + fullText, ['equipe', 'time', 'vendedor', 'vendedores', 'comercial', 'closer']);
const minimal_support_structure = has_team_structure || anyIncludes(structureText + ' ' + fullText, ['assistente', 'apoio', 'atendimento']);
const solo_but_organized = anyIncludes(structureText + ' ' + fullText, ['sozinho', 'eu mesmo']) && executionDensity >= 2;

const clear_sales_process = anyIncludes(fullText, ['crm', 'script', 'funil', 'pipeline', 'processo comercial', 'rotina comercial']);
const some_process = clear_sales_process || executionDensity >= 3;
const intuitive_process = !some_process && executionDensity >= 1;

const mature_operation = executionDensity >= 4;
const functional_operation = executionDensity >= 3;
const initial_but_has_base = executionDensity >= 2;

// investimento
const investmentDensity = countTrue([
  hasValue(investmentText),
  anyIncludes(investmentText, ['investir', 'orcamento', 'orçamento', 'verba']),
  anyIncludes(fullText, ['invisto', 'investe', 'meta ads', 'google ads', 'agencia', 'agência', 'tráfego', 'trafego']),
  anyIncludes(fullText, ['pretendo investir', 'quero investir', 'tenho verba', 'tenho orçamento']),
  anyIncludes(fullText, ['outra empresa', 'outras unidades', 'capital', 'caixa'])
]);

const already_invests_consistently =
  anyIncludes(fullText, ['meta ads', 'google ads', 'agencia atual', 'agência atual', 'verba mensal']) ||
  (investmentDensity >= 3 && anyIncludes(fullText, ['invisto', 'investe', 'anuncio', 'anúncio']));

const already_invests_somewhat =
  already_invests_consistently ||
  investmentDensity >= 2;

const sporadic_investment =
  !already_invests_somewhat && investmentDensity >= 1;

const ready_to_invest_now =
  anyIncludes(fullText + ' ' + investmentText, ['tenho verba', 'tenho orçamento', 'pronto para investir', 'quero contratar', 'quero começar agora']);

const intends_short_term =
  ready_to_invest_now ||
  anyIncludes(fullText + ' ' + investmentText, ['pretendo investir', 'avaliando investimento', 'quero investir em breve', 'planejo investir']) ||
  investmentDensity >= 2;

const evaluating_investment =
  !intends_short_term && anyIncludes(fullText, ['avaliando', 'estudando', 'vendo possibilidade']);

const strong_budget_fit =
  anyIncludes(fullText + ' ' + investmentText, ['5 mil', '10 mil', '8 mil', 'investimento robusto', 'verba forte']);

const good_budget_fit =
  strong_budget_fit || anyIncludes(fullText + ' ' + investmentText, ['3 mil', '4 mil', '2500', '2.500', '3.000']);

const borderline_budget_fit =
  good_budget_fit || anyIncludes(fullText + ' ' + investmentText, ['1500', '1.500', '2 mil', '2.000']);

const weak_budget_signal =
  borderline_budget_fit || investmentDensity >= 1;

const strong_real_capacity =
  anyIncludes(fullText, ['outra empresa', 'outras unidades', 'multiplas unidades', 'múltiplas unidades', 'capital', 'caixa']);

const good_real_capacity =
  strong_real_capacity || investmentDensity >= 2;

const some_potential_capacity =
  good_real_capacity || investmentDensity >= 1;

// conversa
const responsivenessDensity = countTrue([
  textLen(last_user_message) >= 8,
  textLen(last_user_message) >= 20,
  textLen(contextText) >= 10,
  textLen(last_ai_message) > 0
]);

const intentDensity = countTrue([
  hasValue(objectiveText),
  hasValue(serviceInterestText),
  anyIncludes(fullText, ['quero', 'preciso', 'interesse', 'contratar']),
  anyIncludes(fullText, ['clientes', 'vendas', 'agendamentos', 'crescer', 'escala'])
]);

const conversation_flows_well = responsivenessDensity >= 2 && intentDensity >= 1;
const responds_well = responsivenessDensity >= 1;
const responds_basic = textLen(last_user_message) > 0;
const very_travado = responds_basic && !responds_well;

const clear_answers = strongTextCount >= 3 || textLen(last_user_message) >= 25;
const partially_clear = strongTextCount >= 2 || textLen(last_user_message) >= 10;
const vague = responds_basic && !partially_clear;

const strong_commercial_intent = intentDensity >= 3;
const reasonable_intent = intentDensity >= 2;
const generic_interest = intentDensity >= 1;

// penalidades
const only_price_no_context =
  anyIncludes(fullText, ['quanto custa', 'qual valor', 'preco', 'preço']) &&
  summaryCompleteness <= 3 &&
  !has_defined_business &&
  !relevant_pain;

const wants_followers_not_clients =
  anyIncludes(fullText, ['seguidores', 'engajamento']) &&
  !anyIncludes(fullText, ['clientes', 'vendas', 'agendamentos', 'pacientes']);

const out_of_scope_without_openness =
  anyIncludes(fullText, ['designer', 'social media apenas', 'edição de vídeo', 'edicao de video']) &&
  !anyIncludes(fullText, ['tráfego', 'trafego', 'whatsapp', 'vendas', 'comercial']);

const not_decisor_no_access =
  !is_decisor &&
  !has_access_to_decisor &&
  anyIncludes(fullText, ['não sou o responsável', 'nao sou o responsavel', 'não decido', 'nao decido']);

const bad_commitment =
  anyIncludes(fullText, ['só olhando', 'so olhando', 'curiosidade', 'apenas pesquisando']) &&
  summaryCompleteness <= 4 &&
  !reasonable_intent;

// bônus
const multiple_units_or_robust =
  anyIncludes(fullText, ['multiplas unidades', 'múltiplas unidades', 'franquia', 'empresa maior', 'time comercial']) ||
  executionDensity >= 4;

const pain_matches_convertix_core =
  anyIncludes(fullText, ['previsibilidade', 'escala', 'margem', 'comercial', 'estrutura', 'funil', 'crm', 'whatsapp']);

const premium_fit =
  (is_decisor || has_access_to_decisor || partial_access_to_decisor) &&
  (good_budget_fit || strong_budget_fit || strong_real_capacity) &&
  (soon_timing || hot_timing || clear_goal);

// =========================
// Scoring by heuristic quality
// =========================
let score_estrutura = 0;
let score_potencial_comercial = 0;
let score_execucao = 0;
let score_investimento = 0;
let score_conversa = 0;
let score_bonus = 0;
let score_penalty = 0;

// Estrutura 0-20
score_estrutura += scoreByCompleteness(
  countTrue([has_defined_business, already_sells_somewhat, has_identifier]),
  3,
  14
);

score_estrutura += scoreFromBands(summaryCompleteness, [
  { min: 8, score: 6 },
  { min: 5, score: 4 },
  { min: 3, score: 2 }
]);

score_estrutura = clamp(score_estrutura, 0, 20);

// Potencial comercial 0-30
score_potencial_comercial += scoreByCompleteness(
  countTrue([
    is_decisor || has_access_to_decisor || partial_access_to_decisor,
    semi_clear_goal,
    relevant_pain,
    brief_timing || soon_timing || hot_timing
  ]),
  4,
  20
);

score_potencial_comercial += scoreFromBands(strongTextCount, [
  { min: 6, score: 10 },
  { min: 4, score: 7 },
  { min: 2, score: 4 },
  { min: 1, score: 2 }
]);

score_potencial_comercial = clamp(score_potencial_comercial, 0, 30);

// Execução 0-20
score_execucao += scoreByCompleteness(
  countTrue([
    basic_sales_channel,
    minimal_support_structure || solo_but_organized,
    some_process,
    initial_but_has_base
  ]),
  4,
  16
);

score_execucao += scoreFromBands(executionDensity, [
  { min: 4, score: 4 },
  { min: 3, score: 3 },
  { min: 2, score: 2 },
  { min: 1, score: 1 }
]);

score_execucao = clamp(score_execucao, 0, 20);

// Investimento 0-20
score_investimento += scoreByCompleteness(
  countTrue([
    already_invests_somewhat || sporadic_investment,
    intends_short_term || ready_to_invest_now || evaluating_investment,
    weak_budget_signal,
    some_potential_capacity
  ]),
  4,
  16
);

score_investimento += scoreFromBands(investmentDensity, [
  { min: 4, score: 4 },
  { min: 3, score: 3 },
  { min: 2, score: 2 },
  { min: 1, score: 1 }
]);

score_investimento = clamp(score_investimento, 0, 20);

// Conversa 0-10
score_conversa += scoreByCompleteness(
  countTrue([
    responds_well || responds_basic,
    partially_clear,
    generic_interest
  ]),
  3,
  7
);

score_conversa += scoreFromBands(textLen(last_user_message), [
  { min: 60, score: 3 },
  { min: 25, score: 2 },
  { min: 8, score: 1 }
]);

score_conversa = clamp(score_conversa, 0, 10);

// Bônus 0-10
if (multiple_units_or_robust) score_bonus += 4;
if (pain_matches_convertix_core) score_bonus += 3;
if (premium_fit) score_bonus += 3;
score_bonus = clamp(score_bonus, 0, 10);

// Penalidades 0 a -15
if (only_price_no_context) score_penalty -= 4;
if (wants_followers_not_clients) score_penalty -= 5;
if (out_of_scope_without_openness) score_penalty -= 4;
if (not_decisor_no_access) score_penalty -= 4;
if (!has_identifier && summaryCompleteness <= 3) score_penalty -= 5;
if (bad_commitment) score_penalty -= 3;
score_penalty = clamp(score_penalty, -15, 0);

// Score final
let lead_score =
  score_estrutura +
  score_potencial_comercial +
  score_execucao +
  score_investimento +
  score_conversa +
  score_bonus +
  score_penalty;

lead_score = clamp(lead_score, 0, 100);

// Temperatura
let lead_temperature = '';
if (lead_score < 25) lead_temperature = 'frio';
else if (lead_score < 50) lead_temperature = 'morno_inicial';
else if (lead_score < 70) lead_temperature = 'morno_bom';
else if (lead_score < 85) lead_temperature = 'quente';
else lead_temperature = 'premium';

// =========================
// Meeting gate v2
// Menos rígido, mais prudente
// =========================
const contextSignals = countTrue([
  semi_clear_goal,
  relevant_pain || strong_pain,
  has_defined_business || has_partial_business,
  basic_sales_channel,
  already_sells_somewhat || starting_to_sell,
  summaryCompleteness >= 5,
  strongTextCount >= 3
]);

const fitSignals = countTrue([
  reasonable_intent,
  wantsClientsOrGrowth(),
  responds_well || conversation_flows_well,
  is_decisor || has_access_to_decisor || partial_access_to_decisor,
  intends_short_term || already_invests_somewhat || some_potential_capacity,
  has_identifier || summaryCompleteness >= 6
]);

function wantsClientsOrGrowth() {
  return anyIncludes(fullText, ['clientes', 'vendas', 'agendamentos', 'crescer', 'escala', 'previsibilidade', 'resultado']);
}

const hardBlocks = [];
if (only_price_no_context) hardBlocks.push('price_without_context');
if (wants_followers_not_clients) hardBlocks.push('followers_not_clients');
if (out_of_scope_without_openness) hardBlocks.push('out_of_scope');
if (not_decisor_no_access) hardBlocks.push('no_decision_access');

let meeting_gate = 'INVESTIGAR_MAIS';

if (hardBlocks.length > 0 && lead_score < 60) {
  meeting_gate = 'BLOQUEAR_REUNIAO';
} else if (lead_score >= 75 && contextSignals >= 3 && fitSignals >= 3) {
  meeting_gate = has_identifier ? 'ELEGIVEL_REUNIAO' : 'EXCECAO_HUMANA';
} else if (lead_score >= 60 && contextSignals >= 3 && fitSignals >= 2) {
  meeting_gate = has_identifier ? 'ELEGIVEL_REUNIAO' : 'INVESTIGAR_MAIS';
} else if (lead_score >= 45 && (contextSignals >= 2 || fitSignals >= 2)) {
  meeting_gate = 'INVESTIGAR_MAIS';
} else {
  meeting_gate = 'BLOQUEAR_REUNIAO';
}

// =========================
// Suggested operational bias
// =========================
let next_bias = 'QUALIFICAR';

if (meeting_gate === 'ELEGIVEL_REUNIAO') next_bias = 'PREPARAR_REUNIAO';
else if (meeting_gate === 'EXCECAO_HUMANA') next_bias = 'ANALISAR_HUMANO';
else if (lead_temperature === 'frio') next_bias = 'QUALIFICACAO_LEVE';
else next_bias = 'QUALIFICAR_COM_INTENCAO';

// =========================
// Reasoning
// =========================
const score_reasoning = {
  estrutura:
    has_identifier
      ? 'Há base mínima de operação ou presença identificável.'
      : summaryCompleteness >= 5
      ? 'Há contexto relevante, mas o identificador da operação ainda está fraco.'
      : 'Estrutura ainda muito incompleta.',
  potencial_comercial:
    contextSignals >= 4
      ? 'Objetivo, dor, momento e leitura comercial aparecem com boa densidade.'
      : contextSignals >= 2
      ? 'Existe potencial, mas ainda falta consolidar peças do cenário.'
      : 'Potencial comercial ainda raso.',
  execucao:
    executionDensity >= 3
      ? 'Há sinais de canal, estrutura ou processo.'
      : executionDensity >= 2
      ? 'Execução existe, mas ainda pouco clara.'
      : 'Execução ainda muito inicial.',
  investimento:
    investmentDensity >= 3
      ? 'Há sinais consistentes de verba, intenção ou capacidade.'
      : investmentDensity >= 1
      ? 'Há indícios, mas ainda sem firmeza.'
      : 'Investimento pouco claro.',
  conversa:
    reasonable_intent && responds_well
      ? 'A conversa trouxe contexto útil e intenção comercial razoável.'
      : responds_basic
      ? 'A conversa existe, mas ainda precisa aprofundar.'
      : 'Conversa fraca ou superficial.'
};

// =========================
// Output
// =========================
return [
  {
    json: {
      input_snapshot: {
        phone,
        entry_channel,
        lead_status,
        last_intent,
        company_name,
        instagram,
        website,
        google_business_profile,
        email,
        last_user_message,
