        email,
        last_user_message,
        last_ai_message,
        selected_option,
        selected_option_start,
        option_1_start,
        option_2_start,
        atlas_decision: safeStr(atlas.decision),
        atlas_reason: safeStr(atlas.reason)
      },

      lead_score,
      lead_temperature,

      score_estrutura,
      score_potencial_comercial,
      score_execucao,
      score_investimento,
      score_conversa,
      score_bonus,
      score_penalty,

      summary_completeness: summaryCompleteness,
      strong_text_count: strongTextCount,
      context_signals: contextSignals,
      fit_signals: fitSignals,

      hard_blocks: uniq(hardBlocks),
      meeting_gate,
      next_bias,

      score_flags: {
        has_identifier,
        has_strong_identifier,
